const startedAt = new Date().toISOString();
const logId = $input.first().json[0]?.id || $input.first().json?.id;
return [{ json: { log_id: logId, started_at: startedAt } }];

// Build brand configs for Zoho CRM queries
// Each brand has its own Zoho CRM org — uses OAuth2 credentials
const brands = [
  { brand_id: 1, brand_name: 'spa', credential_name: 'Zoho CRM Spa' },
  { brand_id: 2, brand_name: 'aesthetics', credential_name: 'Zoho CRM Aesthetics' },
  { brand_id: 3, brand_name: 'slimming', credential_name: 'Zoho CRM Slimming' }
];

const logId = $input.first().json.log_id;
const startedAt = $input.first().json.started_at;

// Compute 24 hours ago in ISO format
const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

return brands.map(b => ({ json: { ...b, log_id: logId, started_at: startedAt, since } }));

const brandId = $('Build Brand List').item.json.brand_id;
const response = $input.first().json;
const deals = response.data || [];
const today = new Date().toISOString().substring(0, 10);

// Define STL buckets
const buckets = {
  '<1min': { min: 0, max: 1 },
  '1-3min': { min: 1, max: 3 },
  '3-5min': { min: 3, max: 5 },
  '5-15min': { min: 5, max: 15 },
  '15-30min': { min: 15, max: 30 },
  '30min+': { min: 30, max: Infinity }
};

// Initialize counts
const counts = {};
for (const bucket of Object.keys(buckets)) {
  counts[bucket] = 0;
}

let total = 0;

for (const deal of deals) {
  let stlMinutes = null;

  // Use Speed_to_Lead_Minutes field if available
  if (deal.Speed_to_Lead_Minutes != null && deal.Speed_to_Lead_Minutes !== '') {
    stlMinutes = parseFloat(deal.Speed_to_Lead_Minutes);
  }
  // Otherwise compute from Campaign_Entry_Time and First_Contact_Time
  else if (deal.Campaign_Entry_Time && deal.First_Contact_Time) {
    const entry = new Date(deal.Campaign_Entry_Time);
    const contact = new Date(deal.First_Contact_Time);
    stlMinutes = (contact - entry) / 60000;
  }

  if (stlMinutes == null || isNaN(stlMinutes) || stlMinutes < 0) continue;

  total++;

  // Assign to bucket
  for (const [bucket, range] of Object.entries(buckets)) {
    if (stlMinutes >= range.min && stlMinutes < range.max) {
      counts[bucket]++;
      break;
    }
  }
}

// Build output rows
const rows = Object.keys(buckets).map(bucket => ({
  json: {
    date: today,
    brand_id: brandId,
    bucket: bucket,
    count: counts[bucket],
    pct: total > 0 ? parseFloat((counts[bucket] / total * 100).toFixed(2)) : 0
  }
}));

return rows;

const logId = $('Extract Log ID').first().json.log_id;
const startedAt = $('Extract Log ID').first().json.started_at;
const items = $input.all();
const rowsUpserted = items.length;
const durationSec = Math.round((Date.now() - new Date(startedAt).getTime()) / 1000);

return [{ json: { log_id: logId, rows_upserted: rowsUpserted, duration_sec: durationSec } }];

const errorMsg = $input.first().json.execution?.error?.message || 'Unknown error';
let logId = null;
try {
  const execData = $input.first().json.execution?.data?.resultData?.runData;
  if (execData && execData['Extract Log ID']) {
    logId = execData['Extract Log ID'][0]?.data?.main?.[0]?.[0]?.json?.log_id;
  }
} catch(e) {}

return [{ json: { log_id: logId, error_message: errorMsg.substring(0, 1000) } }];
